const file = $input.item.json;
if (!file || !file.name) throw new Error('No file data');

const name = file.name.trim().toLowerCase();

// Only process .txt files
if (!name.endsWith('.txt')) {
  throw new Error('Not a transcript file (must be .txt)');
}

// Extract base name (without .txt)
const baseName = name.replace('.txt', '');

// Determine channel from base name
let channel = "UNKNOWN";
if (baseName.includes('health')) channel = "HEALTH_HACKS";
else if (baseName.includes('money')) channel = "MONEYSTACK";

const ts = new Date().toISOString().split('T')[0].replace(/-/g,'');
const id = Math.random().toString(36).substring(2, 8);
const videoId = `${channel.toLowerCase()}-${ts}-${id}`;

return {videoId, channel, filename: file.name, txtFileId: file.id, baseName, detectedAt: new Date().toISOString()};

// Read transcript from binary data
const transcriptBuffer = $binary.transcript.data;
const transcriptText = transcriptBuffer.toString('utf8');

if (!transcriptText || transcriptText.trim().length < 10) {
  throw new Error('Transcript file is empty or too short');
}

return {
  text: transcriptText.trim(),
  videoId: $node['Detect Transcript File'].json.videoId,
  channel: $node['Detect Transcript File'].json.channel
};

const channel = $json.channel;
const transcript = $json.text;

const prompt = `You are a social media strategist. Generate unique titles/descriptions for this video.

CHANNEL: ${channel}
TRANSCRIPT: ${transcript}

Generate platform-specific content:

TIKTOK: Viral hook, casual tone, emoji-rich
INSTAGRAM: Aspirational story, relatable
YOUTUBE: SEO-optimized, educational

Output ONLY valid JSON: {"tiktok":{"title":"","caption":"","hashtags":[]},"instagram":{"title":"","caption":"","hashtags":[]},"youtube":{"title":"","description":"","tags":[]}}`;

return {prompt, channel, videoId: $json.videoId};

const response = $json.choices[0].message.content;
let content;
try {content = JSON.parse(response);} catch {content = JSON.parse(response.replace(/```json\n?/g,'').replace(/```/g,'').trim());}
return {tiktok: content.tiktok, instagram: content.instagram, youtube: content.youtube};

